// Split incoming file_ids array into one item per file_id.
// The IF guard upstream guarantees at least one id; defensive check kept.

const data = $input.first().json;
const ids = Array.isArray(data.file_ids) ? data.file_ids : [];

return ids.map((file_id, idx) => ({
  json: {
    file_id,
    file_index: idx
  }
}));

// Normalize Slack files.info response and classify the attachment.
// Slack returns { ok, file: {...} }. Map to a flat shape so downstream
// markers/downloads/formatters keep working without changes.

const raw = $input.item.json;
const fileInfo = raw && raw.file ? {
  id: raw.file.id,
  name: raw.file.name || raw.file.title || 'unnamed',
  mime_type: (raw.file.mimetype || '').toLowerCase(),
  size: Number(raw.file.size) || 0,
  url_private_download: raw.file.url_private_download || raw.file.url_private || ''
} : raw;

const config = $('Config').first().json;

const mimeType = (fileInfo.mime_type || '').toLowerCase();
const fileName = fileInfo.name || '';
const size = Number(fileInfo.size) || 0;

const dotIdx = fileName.lastIndexOf('.');
const ext = dotIdx >= 0 ? fileName.slice(dotIdx + 1).toLowerCase() : '';

const TEXT_EXTENSIONS = new Set([
  'log', 'txt', 'out', 'err',
  'json', 'ndjson', 'jsonl', 'yaml', 'yml', 'xml', 'csv', 'tsv', 'toml',
  'md', 'markdown', 'rst', 'conf', 'cfg', 'ini', 'env', 'properties',
  'sh', 'bash', 'zsh', 'fish', 'ps1',
  'py', 'js', 'mjs', 'cjs', 'ts', 'jsx', 'tsx',
  'go', 'rs', 'java', 'kt', 'rb', 'php', 'pl', 'lua',
  'c', 'h', 'cpp', 'hpp', 'cc', 'cs', 'm', 'mm',
  'tf', 'hcl', 'tfvars', 'sql', 'graphql', 'gql', 'dockerfile',
  'html', 'htm', 'css', 'scss', 'sass', 'less', 'vue', 'svelte',
  'patch', 'diff'
]);

const isImage = mimeType.startsWith('image/');
const isTextMime =
  mimeType.startsWith('text/') ||
  mimeType === 'application/json' ||
  mimeType === 'application/ld+json' ||
  mimeType === 'application/xml' ||
  mimeType === 'application/x-yaml' ||
  mimeType === 'application/yaml' ||
  mimeType === 'application/x-sh' ||
  mimeType === 'application/javascript' ||
  mimeType === 'application/x-ndjson' ||
  mimeType === 'application/toml';
const isTextLike = isTextMime || TEXT_EXTENSIONS.has(ext);

let category;
if (isImage && size <= config.MAX_IMAGE_SIZE_BYTES) {
  category = 'image';
} else if (isTextLike && size <= config.MAX_TEXT_SIZE_BYTES) {
  category = 'text_small';
} else if (isTextLike) {
  category = 'text_too_large';
} else {
  category = 'unsupported';
}

return {
  json: {
    ...fileInfo,
    file_extension: ext,
    is_text_like: isTextLike,
    is_image: isImage,
    category
  }
};

// runOnceForEachItem — pairedItem propagation lets us reach back to
// "Classify file" by item index and recover the original file metadata.

const llmOut = $input.item.json;
const fileInfo = $('Classify file').item.json;

// OpenAI Analyze Image returns the model text under different fields
// depending on n8n version. Try common shapes in order.
let description =
  (typeof llmOut.content === 'string' && llmOut.content) ||
  (typeof llmOut.message?.content === 'string' && llmOut.message.content) ||
  (Array.isArray(llmOut.content) && llmOut.content.map(c => c.text || '').join('\n')) ||
  llmOut.text ||
  '[vision model returned no content]';

if (typeof description !== 'string') {
  description = JSON.stringify(description);
}

return {
  json: {
    file_id: fileInfo.id,
    file_name: fileInfo.name,
    mime_type: fileInfo.mime_type,
    size: fileInfo.size,
    is_image: true,
    is_text: false,
    description
  }
};

// runOnceForEachItem. HTTP Request (responseFormat=text) returned the body
// as a string in $json.data. File metadata is recovered via pairedItem from
// "Classify file".
//
// Two-tier size check:
//   tier 1 (bytes): already enforced by "Classify file" + Switch routing.
//   tier 2 (lines): re-checked here for files that fit byte budget but
//                   contain unusually long lines (e.g. minified JSON).

const fileInfo = $('Classify file').item.json;
const config = $('Config').first().json;
const text = typeof $json.data === 'string' ? $json.data : '';

const lineCount = text.length === 0 ? 0 : text.split(/\r\n|\r|\n/).length;
const maxLines = Number(config.MAX_TEXT_LINES) || 300;

if (lineCount > maxLines) {
  return {
    json: {
      file_id: fileInfo.id,
      file_name: fileInfo.name,
      mime_type: fileInfo.mime_type,
      size: fileInfo.size,
      is_image: false,
      is_text: true,
      description: `Attachment ${fileInfo.name} is too large to inline: ${fileInfo.size} bytes / ${lineCount} lines (limit: ${maxLines} lines). Ask the user to share the relevant excerpt.`
    }
  };
}

return {
  json: {
    file_id: fileInfo.id,
    file_name: fileInfo.name,
    mime_type: fileInfo.mime_type,
    size: fileInfo.size,
    is_image: false,
    is_text: true,
    description: `Text content of ${fileInfo.name} (${fileInfo.size} bytes, ${lineCount} lines):\n\n\`\`\`\n${text}\n\`\`\``
  }
};

// Aggregate produced a single item with `attachments: [...]`.
// Build a human-readable block for the AI Agent system prompt.
// Output shape mirrors the "Empty result" Set node so the parent workflow
// can consume the output uniformly.

const attachments = $input.first().json.attachments || [];
const valid = attachments.filter(a => a && a.file_id);

if (valid.length === 0) {
  return [{ json: { attachments_context: '', attachments_count: 0 } }];
}

const blocks = valid.map((a, i) => {
  let tag;
  if (a.is_image) tag = 'image';
  else if (a.is_text) tag = 'text';
  else tag = a.mime_type || 'file';

  const header = `Attachment ${i + 1}: ${a.file_name} [${tag}]`;
  return `${header}\n${a.description}`;
});

return [{
  json: {
    attachments_context: blocks.join('\n\n---\n\n'),
    attachments_count: valid.length
  }
}];
